// Calcular datas: hoje no formato YYYY-MM-DD e início do dia
const agora = new Date();
const hoje = agora.toLocaleDateString('pt-BR', { 
  year: 'numeric', 
  month: '2-digit', 
  day: '2-digit',
  timeZone: 'America/Sao_Paulo'
}).split('/').reverse().join('-');

// Data início: hoje às 00:00 BRT → ISO
const inicioHoje = new Date(agora.getFullYear(), agora.getMonth(), agora.getDate(), 3, 0, 0).toISOString();

return [{ json: { hoje, inicioHoje } }];

// Consolidar métricas por pessoa a partir dos dados do Notion
const items = $input.first().json.results || [];
const hoje = $('Calcular Data Hoje').first().json.hoje;

const consolidado = {
  karine: { fechamentos: 0, reativacoes: 0, falou_com: 0 },
  lucas:  { ativacoes: 0, retencoes: 0, msgs: 0 },
  raquel: { leads: 0, instagram: 0, falou_com: 0 },
  bloqueadores: []
};

for (const item of items) {
  const props = item.properties;
  const pessoa = (props.Pessoa?.select?.name || '').toLowerCase();
  const tipo = props.Tipo?.select?.name || '';

  if (pessoa === 'karine') {
    consolidado.karine.fechamentos  += props.Fechamentos?.number || 0;
    consolidado.karine.reativacoes  += props.Reativações?.number || 0;
    consolidado.karine.falou_com    += props['Falou Com']?.number || 0;
  } else if (pessoa === 'lucas') {
    consolidado.lucas.ativacoes     += props.Ativações?.number || 0;
    consolidado.lucas.retencoes     += props.Reativações?.number || 0;
    consolidado.lucas.msgs          += props['Falou Com']?.number || 0;
  } else if (pessoa === 'raquel') {
    consolidado.raquel.leads        += props['Leads Gerados']?.number || 0;
    consolidado.raquel.falou_com    += props['Falou Com']?.number || 0;
  }

  // Capturar bloqueadores registrados
  const obs = props.Observação?.rich_text?.[0]?.plain_text || '';
  if (obs.toLowerCase().includes('bloqueador') || obs.toLowerCase().includes('problema')) {
    consolidado.bloqueadores.push(`${props.Pessoa?.select?.name}: ${obs.slice(0, 80)}`);
  }
}

// Metas do dia (ajustar conforme sprint)
const metas = {
  karine_fechamentos: 3,
  lucas_ativacoes: 20,
  raquel_leads: 10
};

// Calcular status
const status = (val, meta) => val >= meta ? '🟢' : val >= meta * 0.5 ? '🟡' : '🔴';

const total_cartoes = consolidado.karine.fechamentos;
const total_leads   = consolidado.raquel.leads;

return [{ json: { consolidado, metas, status, total_cartoes, total_leads, hoje } }];

const d = $input.first().json;
const c = d.consolidado;
const m = d.metas;
const s = d.status;
const hoje = d.hoje;

// Formatar data para exibição
const partes = hoje.split('-');
const dataFormatada = `${partes[2]}/${partes[1]}/${partes[0]}`;

// Emoji de status por pessoa
const sk = s(c.karine.fechamentos, m.karine_fechamentos);
const sl = s(c.lucas.ativacoes, m.lucas_ativacoes);
const sr = s(c.raquel.leads, m.raquel_leads);

// Bloqueadores
const blocos = c.bloqueadores.length > 0
  ? c.bloqueadores.map(b => `  ▸ ${b}`).join('\n')
  : '  Nenhum registrado';

const mensagem = `📊 *Resultado SST Card — ${dataFormatada}*

` +
  `👤 *Karine:* ${sk}\n` +
  `  Cartões: *${c.karine.fechamentos}* / ${m.karine_fechamentos} | Reativações: ${c.karine.reativacoes} | Contatos: ${c.karine.falou_com}\n\n` +
  `👤 *Lucas:* ${sl}\n` +
  `  Ativações: *${c.lucas.ativacoes}* / ${m.lucas_ativacoes} | Retenções: ${c.lucas.retencoes}\n\n` +
  `👤 *Raquel:* ${sr}\n` +
  `  Leads: *${c.raquel.leads}* / ${m.raquel_leads} leads\n\n` +
  `━━━━━━━━━━━━━━━━━━\n` +
  `📦 *Consolidado:* ${d.total_cartoes} cartões | ${d.total_leads} leads\n\n` +
  `🔔 *Bloqueadores:*\n${blocos}\n\n` +
  `_Gerado automaticamente às 15h45 | n8n SST_`;

return [{ json: { mensagem } }];

const now = new Date().toISOString();
console.log(`[${now}] Dashboard diário enviado com sucesso.`);
return [{ json: { status: 'ok', timestamp: now } }];

const now = new Date().toISOString();
console.error(`[${now}] Falha ao enviar dashboard diário.`);
return [{ json: { status: 'erro', timestamp: now, dados: $input.first().json } }];
